// ---- Fundory allowlist gate ----
// This n8n instance hosts workflows from multiple unrelated projects.
// Only surface errors from Fundory workflows in our Slack channel + dashboard.
// Keep this array in sync with /lib/n8n/fundory-workflows.ts in the repo.
const FUNDORY_WORKFLOWS = [
  "5. Narrative Library with AI Customization",
  "6. Grant Proposal Generator",
  "add new grants to pipeline",
  "AI Proposal Critic 8",
  "Auto-Submit 11",
  "Award Notification Handler My workflow 13",
  "Budget Generator 7",
  "Central Grants Description Backfill",
  "Centralized Scheduled Grant fetch",
  "Centralized Scheduled Grant fetch - Enrich Description",
  "Daily Org Grant Fetch Scheduler",
  "Discovery Cleanup Replay",
  "Enrich Throttle Queue",
  "_Error Handler Test",
  "Error Notification Handler",
  "funder Analyzer 9",
  "Grant Automation 4: Document Vault Manager",
  "Grant Eligibility Screener + Tracker 2/3",
  "Grant fetch",
  "Grant fetch - Process Chunk",
  "Grant Report Auto-Drafter 14",
  "Org Website Narrative Generator",
  "plane state router15",
  "Process Chunk Throttle Queue",
  "Screening Throttle Queue",
  "search for grants using query",
  "Submission Checklist GeneratorMy workflow 10",
  "Support Request Notifier",
  "WF12 - Post Submission Tracker",
];
const _wfName = ($input.first().json && $input.first().json.workflow && $input.first().json.workflow.name) || null;
if (!_wfName || FUNDORY_WORKFLOWS.indexOf(_wfName) === -1) {
  return [{ json: { should_post: false, skipped_reason: 'non-fundory-workflow', workflow_name: _wfName } }];
}

const supabaseUrl = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const supabaseKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';

const supaHeaders = {
  'apikey': supabaseKey,
  'Authorization': 'Bearer ' + supabaseKey,
  'Content-Type': 'application/json',
};

const input = $input.first().json;
const workflow_name  = (input.workflow && input.workflow.name) || null;
const failed_node    = (input.execution && input.execution.lastNodeExecuted) || null;
const execution_id   = (input.execution && input.execution.id) ? String(input.execution.id) : null;
const execution_mode = (input.execution && input.execution.mode) || null;
const error_message      = (input.execution && input.execution.error && input.execution.error.message) || null;
const error_description  = (input.execution && input.execution.error && input.execution.error.description) || null;
const execution_url      = (input.execution && input.execution.url) || null;

// ---- classify error_type ----
function classify(msg) {
  if (!msg) return 'unknown';
  const m = String(msg).toLowerCase();
  if (m.includes('timeout') || m.includes('timed out') || m.includes('etimedout')) return 'timeout';
  if (m.includes('out of memory') || m.includes('heap') || m.includes('fatal javascript oom')) return 'oom';
  if (m.includes('econnreset') || m.includes('socket hang up') || m.includes('enotfound') || m.includes('eai_again')) return 'network';
  if (m.includes('rate limit') || m.match(/\b429\b/)) return 'rate_limit';
  if (m.includes('quota')) return 'quota';
  if (m.match(/\b5\d\d\b/) || m.includes('internal server error') || m.includes('bad gateway') || m.includes('service unavailable')) return 'http_5xx';
  if (m.match(/\b4\d\d\b/) || m.includes('unauthorized') || m.includes('forbidden') || m.includes('bad request')) return 'http_4xx';
  if (m.includes('syntax error') || m.includes('referenceerror') || m.includes('typeerror') || m.includes('cannot read properties')) return 'script_error';
  return 'other';
}
const error_type = classify(error_message);

// ---- fingerprint ----
const fingerprint = (workflow_name || '') + '::' + (failed_node || '') + '::' + error_type;

// ---- try to extract org_id from the payload ----
let org_id = null;
try {
  const blob = JSON.stringify(input);
  const uuidRe = /[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/gi;
  const candidates = Array.from(new Set((blob.match(uuidRe) || []).map(function(x){return x.toLowerCase();})));
  if (candidates.length > 0) {
    const inList = '(' + candidates.map(function(c){return '"' + c + '"';}).join(',') + ')';
    const lookup = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/organizations?id=in.' + encodeURIComponent(inList) + '&select=id&limit=1',
      headers: Object.assign({}, supaHeaders, { 'Accept': 'application/json' }),
      json: true,
    });
    if (Array.isArray(lookup) && lookup.length > 0) {
      org_id = lookup[0].id;
    }
  }
} catch (e) { /* best effort */ }

const payload = { workflow_name, failed_node, execution_id, execution_mode, error_message, error_description, execution_url, error_type, fingerprint, org_id };

// ---- atomic dedup via DB lock (race-free) ----
// n8n_error_dedup_acquire(fingerprint, window_minutes) returns:
//   true  → caller acquired the lock, post the alert
//   false → another caller already holds the lock for this fingerprint
// Because the function uses INSERT...ON CONFLICT DO UPDATE...WHERE expired
// RETURNING, only one of N concurrent error triggers wins. The rest are
// silently suppressed until the window expires.
const DEDUP_WINDOW_MINUTES = 10;
let should_post = false;
try {
  const ack = await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/rpc/n8n_error_dedup_acquire',
    headers: Object.assign({}, supaHeaders, { 'Accept': 'application/json' }),
    body: JSON.stringify({ p_fingerprint: fingerprint, p_window_minutes: DEDUP_WINDOW_MINUTES }),
    json: true,
  });
  // PostgREST returns the scalar boolean directly when the function returns BOOLEAN.
  should_post = ack === true || ack === 'true';
} catch (e) {
  // If the dedup check fails, fail OPEN (post) so we don't silently lose alerts.
  should_post = true;
}

// ---- always log every occurrence to the audit table ----
// NOTE: payload includes error_description for the Slack node, but the
// n8n_workflow_errors table has no such column — sending it causes
// PostgREST 400 which the catch below swallows. Build a DB-only payload
// that matches the table schema.
try {
  const dbPayload = { workflow_name, failed_node, execution_id, execution_mode, error_message: (error_description || error_message), execution_url, error_type, fingerprint, org_id };
  await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/n8n_workflow_errors',
    headers: Object.assign({}, supaHeaders, { 'Prefer': 'return=minimal' }),
    body: JSON.stringify(dbPayload),
  });
} catch (e) { console.error('[ErrorHandler] Supabase log failed:', e && e.message || e); }

return [{
  json: Object.assign({}, payload, {
    should_post: should_post,
    dedup_window_minutes: DEDUP_WINDOW_MINUTES,
  }),
}];

